// app.js

const clientId = 'your_client_id';
const redirectUri = encodeURIComponent('https://yourredirecturi.com/callback');
const authorizationUrl = `https://auth.example.com/oauth/authorize?response_type=code&client_id=${clientId}&redirect_uri=${redirectUri}&scope=read%20write`;

function login() {
  window.location.href = authorizationUrl;
}

async function handleCallback() {
  const urlParams = new URLSearchParams(window.location.search);
  const code = urlParams.get('code');

  if (code) {
    try {
      const tokenResponse = await fetch(`https://auth.example.com/oauth/token`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded'
        },
        body: `grant_type=authorization_code&code=${code}&redirect_uri=${redirectUri}&client_id=${clientId}`
      });

      if (!tokenResponse.ok) {
        throw new Error('Failed to fetch tokens');
      }

      const tokenData = await tokenResponse.json();
      localStorage.setItem('access_token', tokenData.access_token);
      localStorage.setItem('refresh_token', tokenData.refresh_token);

      // Redirect to the home page or another authenticated route
      window.location.href = '/';
    } catch (error) {
      console.error('Error handling callback:', error);
    }
  } else {
    console.error('No authorization code received');
  }
}

async function fetchApi(url, options = {}) {
  const token = localStorage.getItem('access_token');

  if (!token) {
    throw new Error('No access token found');
  }

  return await fetch(url, {
    ...options,
    headers: {
      ...options.headers,
      'Authorization': `Bearer ${token}`
    }
  });
}

if (window.location.pathname === '/callback') {
  handleCallback();
} else if (!localStorage.getItem('access_token')) {
  login();
}